#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>
#include <algorithm>

// Constants for SELU
constexpr float ALPHA = 1.6732632423543772848170429916717f;
constexpr float SCALE = 1.0507009873554804934193349852946f;
constexpr float LAMBDA = 1.0507009873554804934193349852946f;
constexpr float NEG_ALPHA_LAMBDA = -1.7580993408473768599402175208123f;

template<typename T>
__device__ __forceinline__ T selu_compute(T x) {
    return (x >= 0) ? (SCALE * x) : (LAMBDA * (ALPHA * expf(x) - ALPHA));
}

template<>
__device__ __forceinline__ half selu_compute(half x) {
    float fx = __half2float(x);
    float result = (fx >= 0) ? (SCALE * fx) : (LAMBDA * (ALPHA * expf(fx) - ALPHA));
    return __float2half(result);
}

// Robust kernel using grid-stride loop with explicit bounds
// Each thread processes elements with stride = total_threads
// This ensures each element is processed exactly once
template<typename T>
__global__ void selu_kernel_robust(const T* __restrict__ input, T* __restrict__ output, int64_t size) {
    // Grid-stride loop: each thread processes elements separated by total threads
    const int64_t total_threads = blockDim.x * gridDim.x;
    const int64_t tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Each thread starts at its unique thread ID and strides by total_threads
    for (int64_t element_idx = tid; element_idx < size; element_idx += total_threads) {
        T x = input[element_idx];
        output[element_idx] = selu_compute(x);
    }
}

// Specialized kernel for float32 with vectorized loads/stores
// Uses explicit bounds computation to avoid overlap
__global__ void selu_kernel_float32_robust(const float* __restrict__ input, float* __restrict__ output, int64_t size) {
    const int64_t total_threads = blockDim.x * gridDim.x;
    const int64_t tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Process 4 elements at a time when possible
    const int64_t vectorized_size = (size / 4) * 4;

    // Vectorized processing for aligned segments
    for (int64_t base_idx = tid * 4; base_idx < vectorized_size; base_idx += total_threads * 4) {
        // Load 4 floats at once
        float4 in = *reinterpret_cast<const float4*>(&input[base_idx]);

        // Compute SELU
        float4 out;
        out.x = (in.x >= 0) ? (SCALE * in.x) : (LAMBDA * (ALPHA * expf(in.x) - ALPHA));
        out.y = (in.y >= 0) ? (SCALE * in.y) : (LAMBDA * (ALPHA * expf(in.y) - ALPHA));
        out.z = (in.z >= 0) ? (SCALE * in.z) : (LAMBDA * (ALPHA * expf(in.z) - ALPHA));
        out.w = (in.w >= 0) ? (SCALE * in.w) : (LAMBDA * (ALPHA * expf(in.w) - ALPHA));

        // Store 4 floats at once
        *reinterpret_cast<float4*>(&output[base_idx]) = out;
    }

    // Handle remaining elements (scalar processing)
    for (int64_t element_idx = tid + vectorized_size; element_idx < size; element_idx += total_threads) {
        float x = input[element_idx];
        output[element_idx] = (x >= 0) ? (SCALE * x) : (LAMBDA * (ALPHA * expf(x) - ALPHA));
    }
}

torch::Tensor selu_cuda_robust(torch::Tensor input) {
    auto output = torch::empty_like(input);
    int64_t size = input.numel();

    if (size == 0) {
        return output;
    }

    // Calculate optimal launch configuration
    int device;
    cudaGetDevice(&device);
    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, device);

    const int max_threads_per_block = prop.maxThreadsPerBlock;
    const int warp_size = prop.warpSize;

    if (input.scalar_type() == torch::kFloat32) {
        // Use robust vectorized kernel for float32
        const int block_size = std::min(256, max_threads_per_block);
        // Calculate grid size for good occupancy: at least 4 warps per SM
        int num_sm = prop.multiProcessorCount;
        int grid_size = num_sm * 4;

        // Adjust grid_size to ensure all elements are covered
        // Each thread processes multiple elements via the loop
        if (grid_size > 65535) grid_size = 65535;

        selu_kernel_float32_robust<<<grid_size, block_size>>>(
            input.data_ptr<float>(),
            output.data_ptr<float>(),
            size
        );
    } else {
        // Generic robust kernel for other types
        const int block_size = std::min(256, max_threads_per_block);
        int num_sm = prop.multiProcessorCount;
        int grid_size = num_sm * 4;
        if (grid_size > 65535) grid_size = 65535;

        AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "selu_cuda_robust", [&] {
            if (input.scalar_type() == torch::kFloat16) {
                selu_kernel_robust<half><<<grid_size, block_size>>>(
                    reinterpret_cast<half*>(input.data_ptr<torch::Half>()),
                    reinterpret_cast<half*>(output.data_ptr<torch::Half>()),
