class ModelRobust(nn.Module):
    """
    Robust model that performs SELU activation using robust CUDA kernel.
    """
    def __init__(self):
        super(ModelRobust, self).__init__()
        self.selu_cuda = selu_extension.selu_cuda_robust

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies robust SELU activation to the input tensor using robust CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of any shape.

        Returns:
            torch.Tensor: Output tensor with SELU applied, same shape as input.
        """
        # Only use custom kernel if tensor is on CUDA
        if x.is_cuda:
            return self.selu_cuda(x)
        else:
            # Fallback to PyTorch's implementation for CPU
            return torch.selu(x)
